     1→import { NextResponse } from "next/server";
     2→import Stripe from "stripe";
     3→
     4→const LOOKUP_KEY = "paywall_times_monthly";
     5→
     6→export async function POST(request: Request) {
     7→  const secretKey = process.env.STRIPE_SECRET_KEY;
     8→
     9→  if (!secretKey) {
    10→    return NextResponse.json(
    11→      { error: "Stripe is not configured. Add STRIPE_SECRET_KEY to .env.local" },
    12→      { status: 500 }
    13→    );
    14→  }
    15→
    16→  try {
    17→    const body = await request.json().catch(() => ({}));
    18→    const walletAddress: string | null = body.walletAddress || null;
    19→
    20→    const stripe = new Stripe(secretKey);
    21→
    22→    // --- Find or create the recurring price ---
    23→    const existingPrices = await stripe.prices.list({
    24→      lookup_keys: [LOOKUP_KEY],
    25→      limit: 1,
    26→    });
    27→
    28→    let priceId: string;
    29→
    30→    if (existingPrices.data.length > 0) {
    31→      priceId = existingPrices.data[0].id;
    32→    } else {
    33→      const product = await stripe.products.create({
    34→        name: "The Paywall Times Monthly Subscription",
    35→      });
    36→      const price = await stripe.prices.create({
    37→        product: product.id,
    38→        unit_amount: 999,
    39→        currency: "usd",
    40→        recurring: { interval: "month" },
    41→        lookup_key: LOOKUP_KEY,
    42→      });
    43→      priceId = price.id;
    44→    }
    45→
    46→    // --- Find or create customer by walletAddress ---
    47→    let customer: Stripe.Customer | undefined;
    48→
    49→    if (walletAddress) {
    50→      const search = await stripe.customers.search({
    51→        query: `metadata["walletAddress"]:"${walletAddress}"`,
    52→      });
    53→      if (search.data.length > 0) {
    54→        customer = search.data[0];
    55→      }
    56→    }
    57→
    58→    if (!customer) {
    59→      customer = await stripe.customers.create({
    60→        metadata: walletAddress ? { walletAddress } : {},
    61→      });
    62→    }
    63→
    64→    // --- Reuse an existing incomplete subscription if present ---
    65→    const existingSubs = await stripe.subscriptions.list({
    66→      customer: customer.id,
    67→      status: "incomplete",
    68→      limit: 1,
    69→    });
    70→
    71→    if (existingSubs.data.length > 0) {
    72→      const existing = existingSubs.data[0];
    73→      const invoice = await stripe.invoices.retrieve(
    74→        existing.latest_invoice as string,
    75→        { expand: ["confirmation_secret"] }
    76→      );
    77→      const clientSecret = invoice.confirmation_secret?.client_secret;
    78→      if (clientSecret) {
    79→        return NextResponse.json({
    80→          clientSecret,
    81→          subscriptionId: existing.id,
    82→        });
    83→      }
    84→    }
    85→
    86→    // --- Create new subscription ---
    87→    const subscription = await stripe.subscriptions.create({
    88→      customer: customer.id,
    89→      items: [{ price: priceId }],
    90→      payment_behavior: "default_incomplete",
    91→      payment_settings: {
    92→        save_default_payment_method: "on_subscription",
    93→      },
    94→      metadata: {
    95→        ...(walletAddress ? { walletAddress, mintNft: "true" } : {}),
    96→      },
    97→      expand: ["latest_invoice.confirmation_secret"],
    98→    });
    99→
   100→    const latestInvoice = subscription.latest_invoice as Stripe.Invoice;
   101→    const clientSecret = latestInvoice.confirmation_secret!.client_secret;
   102→
   103→    return NextResponse.json({
   104→      clientSecret,
   105→      subscriptionId: subscription.id,
   106→    });
   107→  } catch (err) {
   108→    const message = err instanceof Error ? err.message : "Unknown error";
   109→    return NextResponse.json({ error: message }, { status: 500 });
   110→  }
   111→}
   112→

