    44→  if (!res.ok) {
    45→    const text = await res.text();
    46→    return { success: false, error: `Engine responded ${res.status}: ${text}` };
    47→  }
    48→
    49→  const data = await res.json();
    50→  return { success: true, queueId: data.result?.queueId };
    51→}
